import{_ as a,c as r,o as d,a1 as e}from"./chunks/framework.DILC4Csi.js";const q=JSON.parse('{"title":"最佳实践与避坑指南：用对技能，避免常见陷阱 | Superpowers 教程","description":"掌握 Superpowers 的最佳实践，避免 AI 代理常见的偷懒和合理化行为。学习 TDD 铁律、系统化调试、证据优先、早期代码审查等核心原则，识别并阻止 AI 代理的 12 种常见合理化借口。","frontmatter":{"title":"最佳实践与避坑指南：用对技能，避免常见陷阱 | Superpowers 教程","sidebarTitle":"避坑指南","subtitle":"最佳实践与避坑指南：用对技能，避免常见陷阱","description":"掌握 Superpowers 的最佳实践，避免 AI 代理常见的偷懒和合理化行为。学习 TDD 铁律、系统化调试、证据优先、早期代码审查等核心原则，识别并阻止 AI 代理的 12 种常见合理化借口。","tags":["最佳实践","避坑指南","TDD","调试"],"prerequisite":["start-using-skills"],"order":250},"headers":[],"relativePath":"zh/obra/superpowers/faq/best-practices/index.md","filePath":"zh/obra/superpowers/faq/best-practices/index.md"}'),o={name:"zh/obra/superpowers/faq/best-practices/index.md"};function i(l,t,s,n,u,h){return d(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="最佳实践与避坑指南-用对技能-避免常见陷阱" tabindex="-1">最佳实践与避坑指南：用对技能，避免常见陷阱 <a class="header-anchor" href="#最佳实践与避坑指南-用对技能-避免常见陷阱" aria-label="Permalink to &quot;最佳实践与避坑指南：用对技能，避免常见陷阱&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>立即识别 AI 代理的合理化借口，阻止其偷懒行为</li><li>掌握 TDD、系统化调试、证据优先等核心铁律</li><li>避免常见的反模式，减少返工和调试时间</li><li>建立高效的协作习惯，与 AI 代理达成质量共识</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你花了几个小时和 AI 代理一起开发，最后却发现：</p><ul><li>代码没有测试，功能一堆 bug</li><li>AI 说&quot;应该可以了&quot;，一运行就报错</li><li>重复改了三次问题，每次都引入新 bug</li><li>AI 说服你跳过技能，&quot;这次很简单&quot;</li><li>代码审查时才发现实现了错误的功能</li></ul><p><strong>这不是 AI 不够聪明，是你让 AI&quot;偷懒&quot;了。</strong></p><h2 id="superpowers-的五大铁律" tabindex="-1">Superpowers 的五大铁律 <a class="header-anchor" href="#superpowers-的五大铁律" aria-label="Permalink to &quot;Superpowers 的五大铁律&quot;">​</a></h2><p>Superpowers 不是简单的工具集，它强制 AI 代理遵循五大铁律：</p><table tabindex="0"><thead><tr><th>铁律</th><th>核心内容</th><th>违反的代价</th></tr></thead><tbody><tr><td><strong>1% 原则</strong></td><td>即使只有 1% 可能，也必须调用技能</td><td>AI 会跳过必要的检查，导致漏做工作</td></tr><tr><td><strong>TDD 铁律</strong></td><td>无失败测试不写生产代码</td><td>代码不可测试、难以维护、隐藏 bug</td></tr><tr><td><strong>调试铁律</strong></td><td>无根因不修复</td><td>症状修复、问题复发、时间浪费</td></tr><tr><td><strong>证据铁律</strong></td><td>无证据不声称完成</td><td>虚假进度、信任破裂、返工</td></tr><tr><td><strong>审查铁律</strong></td><td>早期频繁审查</td><td>技术债积累、后期返工成本高</td></tr></tbody></table><h2 id="一、技能调用铁律-防止-ai-偷懒" tabindex="-1">一、技能调用铁律：防止 AI 偷懒 <a class="header-anchor" href="#一、技能调用铁律-防止-ai-偷懒" aria-label="Permalink to &quot;一、技能调用铁律：防止 AI 偷懒&quot;">​</a></h2><h3 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><p><strong>即使只有 1% 可能，也必须调用技能。</strong></p><p>AI 代理很擅长&quot;合理化&quot;——找各种理由跳过必要的工作流程。</p><h3 id="常见合理化借口-vs-真相" tabindex="-1">常见合理化借口 vs 真相 <a class="header-anchor" href="#常见合理化借口-vs-真相" aria-label="Permalink to &quot;常见合理化借口 vs 真相&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI 的借口</th><th>真相</th><th>应对方法</th></tr></thead><tbody><tr><td>&quot;这只是个简单问题&quot;</td><td>问题就是任务，检查技能</td><td>坚持调用技能</td></tr><tr><td>&quot;我需要更多上下文&quot;</td><td>技能检查在澄清问题之前</td><td>先调技能，再问问题</td></tr><tr><td>&quot;让我先探索代码库&quot;</td><td>技能会告诉你如何探索</td><td>先调技能，按技能指引探索</td></tr><tr><td>&quot;我可以快速查 git/文件&quot;</td><td>文件缺少对话上下文</td><td>先调技能，再读文件</td></tr><tr><td>&quot;让我先收集信息&quot;</td><td>技能会告诉你如何收集信息</td><td>先调技能，再收集</td></tr><tr><td>&quot;这不需要正式技能&quot;</td><td>如果有技能，就使用它</td><td>坚持使用</td></tr><tr><td>&quot;我记得这个技能&quot;</td><td>技能会更新，读最新版</td><td>每次都读技能</td></tr><tr><td>&quot;这不算任务&quot;</td><td>任何行动都是任务</td><td>坚持调用技能</td></tr><tr><td>&quot;技能是杀鸡用牛刀&quot;</td><td>简单事情会变复杂</td><td>坚持使用技能</td></tr><tr><td>&quot;我先做这一件事&quot;</td><td>做任何事前先检查</td><td>坚持调用技能</td></tr><tr><td>&quot;感觉这样很高效&quot;</td><td>无纪律行动浪费时间</td><td>技能防止低效</td></tr><tr><td>&quot;我知道什么意思&quot;</td><td>知道概念≠使用技能</td><td>必须调用技能</td></tr></tbody></table><h3 id="技能优先级" tabindex="-1">技能优先级 <a class="header-anchor" href="#技能优先级" aria-label="Permalink to &quot;技能优先级&quot;">​</a></h3><p>当多个技能可能适用时，按此顺序：</p><ol><li><strong>流程技能优先</strong>（brainstorming、debugging）— 决定如何处理任务</li><li><strong>实现技能其次</strong>（TDD、review）— 引导执行</li></ol><p>示例：</p><ul><li>&quot;构建 X&quot; → 先 brainstorming，再实现技能</li><li>&quot;修复这个 bug&quot; → 先 debugging，再 TDD</li></ul><h2 id="二、tdd-铁律-拒绝测试后补" tabindex="-1">二、TDD 铁律：拒绝测试后补 <a class="header-anchor" href="#二、tdd-铁律-拒绝测试后补" aria-label="Permalink to &quot;二、TDD 铁律：拒绝测试后补&quot;">​</a></h2><h3 id="核心原则-1" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-1" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO PRODUCTION CODE WITHOUT A FAILING TEST FIRST</span></span></code></pre></div><p>写代码前没看到测试失败？你没证明它测试正确。</p><h3 id="red-green-refactor-循环" tabindex="-1">RED-GREEN-REFACTOR 循环 <a class="header-anchor" href="#red-green-refactor-循环" aria-label="Permalink to &quot;RED-GREEN-REFACTOR 循环&quot;">​</a></h3><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    red[RED&lt;br/&gt;写失败测试] --&gt; verify_red{验证失败}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_red -- 正确失败 --&gt; green[GREEN&lt;br/&gt;最小代码]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_red -- 错误失败 --&gt; red</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    green --&gt; verify_green{验证通过}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_green -- 全绿 --&gt; refactor[REFACTOR&lt;br/&gt;清理代码]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_green -- 有失败 --&gt; green</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    refactor --&gt; verify_green</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    verify_green -- 全绿 --&gt; next[下一步]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    next --&gt; red</span></span></code></pre></div><h3 id="常见合理化借口" tabindex="-1">常见合理化借口 <a class="header-anchor" href="#常见合理化借口" aria-label="Permalink to &quot;常见合理化借口&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI 的借口</th><th>真相</th></tr></thead><tbody><tr><td>&quot;太简单不需要测试&quot;</td><td>简单代码会坏。测试花 30 秒。</td></tr><tr><td>&quot;我之后再写测试&quot;</td><td>测试立即通过证明什么都没测。</td></tr><tr><td>&quot;测试后补也一样&quot;</td><td>测试后补回答&quot;这是做什么&quot;，测试先回答&quot;应该做什么&quot;</td></tr><tr><td>&quot;我已经手动测试所有边界&quot;</td><td>临时测试≠系统化。无记录，不能重跑。</td></tr><tr><td>&quot;删除 X 小时工作太浪费&quot;</td><td>沉没成本谬误。保留未验证代码是技术债。</td></tr><tr><td>&quot;保留作为参考，先写测试&quot;</td><td>你会调整它，那是测试后。删除就是删除。</td></tr><tr><td>&quot;需要先探索&quot;</td><td>可以。丢掉探索代码，从 TDD 开始。</td></tr><tr><td>&quot;测试难=设计不清楚&quot;</td><td>听从测试。难测=难用。</td></tr><tr><td>&quot;TDD 会拖慢我&quot;</td><td>TDD 比调试快。实用=测试先。</td></tr><tr><td>&quot;手动测试更快&quot;</td><td>手动不证明边界。每次改动都要重测。</td></tr><tr><td>&quot;现有代码没测试&quot;</td><td>你在改进它。给现有代码加测试。</td></tr></tbody></table><h3 id="red-flags-立即停止" tabindex="-1">Red Flags：立即停止 <a class="header-anchor" href="#red-flags-立即停止" aria-label="Permalink to &quot;Red Flags：立即停止&quot;">​</a></h3><ul><li>测试前写代码</li><li>实现后测试</li><li>测试立即通过</li><li>无法解释测试为何失败</li><li>&quot;之后再补测试&quot;</li><li>合理化&quot;就这一次&quot;</li><li>&quot;我已经手动测试了&quot;</li><li>&quot;测试后补也一样&quot;</li><li>&quot;是精神不是仪式&quot;</li><li>&quot;保留作为参考&quot;或&quot;调整现有代码&quot;</li><li>&quot;已经花了 X 小时，删除浪费&quot;</li><li>&quot;TDD 教条主义，我很务实&quot;</li><li>&quot;这次不同，因为...&quot;</li></ul><p><strong>所有这些意味着：删除代码，用 TDD 重新开始。</strong></p><h2 id="三、调试铁律-拒绝盲目修复" tabindex="-1">三、调试铁律：拒绝盲目修复 <a class="header-anchor" href="#三、调试铁律-拒绝盲目修复" aria-label="Permalink to &quot;三、调试铁律：拒绝盲目修复&quot;">​</a></h2><h3 id="核心原则-2" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-2" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO FIXES WITHOUT ROOT CAUSE INVESTIGATION FIRST</span></span></code></pre></div><p>没完成根因调查前不能提修复方案。</p><h3 id="四阶段系统化调试" tabindex="-1">四阶段系统化调试 <a class="header-anchor" href="#四阶段系统化调试" aria-label="Permalink to &quot;四阶段系统化调试&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>核心活动</th><th>成功标准</th></tr></thead><tbody><tr><td><strong>1. 根因调查</strong></td><td>读错误信息、复现、检查变更、收集证据</td><td>理解 WHAT 和 WHY</td></tr><tr><td><strong>2. 模式分析</strong></td><td>找工作示例、对比参考</td><td>识别差异</td></tr><tr><td><strong>3. 假设测试</strong></td><td>形成理论、最小测试</td><td>确认或新假设</td></tr><tr><td><strong>4. 实施</strong></td><td>创建测试、修复、验证</td><td>bug 修复、测试通过</td></tr></tbody></table><h3 id="常见合理化借口-1" tabindex="-1">常见合理化借口 <a class="header-anchor" href="#常见合理化借口-1" aria-label="Permalink to &quot;常见合理化借口&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI 的借口</th><th>真相</th></tr></thead><tbody><tr><td>&quot;问题简单，不需要流程&quot;</td><td>简单问题也有根因。流程对简单 bug 更快。</td></tr><tr><td>&quot;紧急，没时间走流程&quot;</td><td>系统化调试比猜测乱试更快。</td></tr><tr><td>&quot;先试这个，再调查&quot;</td><td>第一次修复设定模式。从一开始就做对。</td></tr><tr><td>&quot;我会写测试验证修复有效&quot;</td><td>未测试修复不持久。测试先证明它。</td></tr><tr><td>&quot;一次多个修复省时间&quot;</td><td>无法隔离有效修复。引入新 bug。</td></tr><tr><td>&quot;参考太长，我会调整模式&quot;</td><td>部分理解保证 bug。完整阅读。</td></tr><tr><td>&quot;我看到问题了，让我修复&quot;</td><td>看到症状≠理解根因。</td></tr><tr><td>&quot;再试一次修复&quot;（2+ 次失败后）</td><td>3+ 次失败=架构问题。质疑模式，别再修。</td></tr></tbody></table><h3 id="red-flags-立即停止-1" tabindex="-1">Red Flags：立即停止 <a class="header-anchor" href="#red-flags-立即停止-1" aria-label="Permalink to &quot;Red Flags：立即停止&quot;">​</a></h3><ul><li>&quot;快速修复，以后调查&quot;</li><li>&quot;试试改 X 看能否工作&quot;</li><li>&quot;添加多个改动，运行测试&quot;</li><li>&quot;跳过测试，我会手动验证&quot;</li><li>&quot;可能是 X，让我修复&quot;</li><li>&quot;我不完全理解但这可能行&quot;</li><li>&quot;模式说 X 但我会不同适应&quot;</li><li>&quot;列出主要问题：[列出修复，无调查]&quot;</li><li>提方案前未追踪数据流</li><li><strong>&quot;再试一次修复&quot;</strong>（已试 2+ 次）</li><li><strong>每次修复揭示不同位置新问题</strong></li></ul><p><strong>所有这些意味着：停止，回到阶段 1。</strong></p><p><strong>如果 3+ 次修复失败：质疑架构。</strong></p><h2 id="四、证据铁律-拒绝虚假完成" tabindex="-1">四、证据铁律：拒绝虚假完成 <a class="header-anchor" href="#四、证据铁律-拒绝虚假完成" aria-label="Permalink to &quot;四、证据铁律：拒绝虚假完成&quot;">​</a></h2><h3 id="核心原则-3" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-3" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NO COMPLETION CLAIMS WITHOUT FRESH VERIFICATION EVIDENCE</span></span></code></pre></div><p>如果本消息没运行验证命令，你不能声称它通过。</p><h3 id="闸门函数" tabindex="-1">闸门函数 <a class="header-anchor" href="#闸门函数" aria-label="Permalink to &quot;闸门函数&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>在声称任何状态或表达满意度之前：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 识别：什么命令证明此声称？</span></span>
<span class="line"><span>2. 运行：执行完整命令（全新、完整）</span></span>
<span class="line"><span>3. 读取：完整输出、检查退出码、统计失败</span></span>
<span class="line"><span>4. 验证：输出是否确认声称？</span></span>
<span class="line"><span>   - 否：陈述实际状态及证据</span></span>
<span class="line"><span>   - 是：陈述声称并提供证据</span></span>
<span class="line"><span>5. 只有这时：发出声称</span></span>
<span class="line"><span></span></span>
<span class="line"><span>跳过任何步骤=说谎，不是验证</span></span></code></pre></div><h3 id="常见合理化借口-2" tabindex="-1">常见合理化借口 <a class="header-anchor" href="#常见合理化借口-2" aria-label="Permalink to &quot;常见合理化借口&quot;">​</a></h3><table tabindex="0"><thead><tr><th>AI 的借口</th><th>真相</th></tr></thead><tbody><tr><td>&quot;应该现在可以了&quot;</td><td>运行验证</td></tr><tr><td>&quot;我有信心&quot;</td><td>信心≠证据</td></tr><tr><td>&quot;就这一次&quot;</td><td>无例外</td></tr><tr><td>&quot;Linter 通过&quot;</td><td>Linter≠编译器</td></tr><tr><td>&quot;代理说成功&quot;</td><td>独立验证</td></tr><tr><td>&quot;我累了&quot;</td><td>疲劳不是借口</td></tr><tr><td>&quot;部分检查足够&quot;</td><td>部分证明什么都没有</td></tr><tr><td>&quot;不同措辞所以规则不适用&quot;</td><td>精神大于字面</td></tr></tbody></table><h3 id="red-flags-立即停止-2" tabindex="-1">Red Flags：立即停止 <a class="header-anchor" href="#red-flags-立即停止-2" aria-label="Permalink to &quot;Red Flags：立即停止&quot;">​</a></h3><ul><li>使用&quot;应该&quot;、&quot;可能&quot;、&quot;似乎&quot;</li><li>验证前表达满意（&quot;好！&quot;、&quot;完美！&quot;、&quot;完成！&quot;）</li><li>准备 commit/push/PR 前不验证</li><li>信任代理成功报告</li><li>依赖部分验证</li><li>想着&quot;就这一次&quot;</li><li>疲惫并希望工作结束</li><li><strong>任何暗示成功但未运行验证的措辞</strong></li></ul><h2 id="五、代码审查铁律-早期频繁审查" tabindex="-1">五、代码审查铁律：早期频繁审查 <a class="header-anchor" href="#五、代码审查铁律-早期频繁审查" aria-label="Permalink to &quot;五、代码审查铁律：早期频繁审查&quot;">​</a></h2><h3 id="核心原则-4" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-4" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><p><strong>审查要早、审查要频。</strong></p><h3 id="何时请求审查" tabindex="-1">何时请求审查 <a class="header-anchor" href="#何时请求审查" aria-label="Permalink to &quot;何时请求审查&quot;">​</a></h3><p><strong>强制：</strong></p><ul><li>子代理驱动开发的每个任务后</li><li>完成主要功能后</li><li>合并到主分支前</li></ul><p><strong>可选但有价值：</strong></p><ul><li>卡住时（新视角）</li><li>重构前（基线检查）</li><li>修复复杂 bug 后</li></ul><h3 id="red-flags-永不" tabindex="-1">Red Flags：永不 <a class="header-anchor" href="#red-flags-永不" aria-label="Permalink to &quot;Red Flags：永不&quot;">​</a></h3><ul><li>因为&quot;简单&quot;跳过审查</li><li>忽略严重问题</li><li>带未修复重要问题继续</li><li>争辩有效技术反馈</li><li>信任代理报告，不查 VCS diff</li></ul><h2 id="六、计划编写-假设工程师无上下文" tabindex="-1">六、计划编写：假设工程师无上下文 <a class="header-anchor" href="#六、计划编写-假设工程师无上下文" aria-label="Permalink to &quot;六、计划编写：假设工程师无上下文&quot;">​</a></h2><h3 id="核心原则-5" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-5" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><p><strong>假设工程师零上下文、品味可疑。</strong></p><p>提供他们需要的所有信息：每个任务改哪些文件、代码、测试、文档参考、如何测试。把整个计划分解为 bite-sized 任务。</p><h3 id="关键原则" tabindex="-1">关键原则 <a class="header-anchor" href="#关键原则" aria-label="Permalink to &quot;关键原则&quot;">​</a></h3><ul><li><strong>DRY</strong>：不要重复代码</li><li><strong>YAGNI</strong>：不需要的不要做</li><li><strong>TDD</strong>：每个功能先写测试</li><li><strong>频繁提交</strong>：每完成任务后 commit</li></ul><h2 id="七、设计阶段-一次一个问题" tabindex="-1">七、设计阶段：一次一个问题 <a class="header-anchor" href="#七、设计阶段-一次一个问题" aria-label="Permalink to &quot;七、设计阶段：一次一个问题&quot;">​</a></h2><h3 id="核心原则-6" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-6" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><p><strong>一次只问一个问题。不要用多个问题压倒用户。</strong></p><h3 id="关键原则-1" tabindex="-1">关键原则 <a class="header-anchor" href="#关键原则-1" aria-label="Permalink to &quot;关键原则&quot;">​</a></h3><ul><li>多选题优于开放式（当可能时）</li><li><strong>YAGNI 无情</strong>：从所有设计中移除不必要功能</li><li>探索替代方案：定案前总是提 2-3 种方法</li><li>增量验证：分段呈现设计，每段确认</li></ul><h2 id="八、子代理驱动-两阶段审查" tabindex="-1">八、子代理驱动：两阶段审查 <a class="header-anchor" href="#八、子代理驱动-两阶段审查" aria-label="Permalink to &quot;八、子代理驱动：两阶段审查&quot;">​</a></h2><h3 id="核心原则-7" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-7" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><p><strong>每个任务用新鲜子代理 + 两阶段审查（先符合规格再代码质量）= 高质量、快迭代。</strong></p><h3 id="red-flags-永不-1" tabindex="-1">Red Flags：永不 <a class="header-anchor" href="#red-flags-永不-1" aria-label="Permalink to &quot;Red Flags：永不&quot;">​</a></h3><ul><li>未经用户明确同意在 main/master 分支开始实现</li><li>跳过审查（规格符合性或代码质量）</li><li>带未修复问题继续</li><li>并发派多个实现子代理（冲突）</li><li>让子代理读计划文件（提供完整文本）</li><li>跳过场景设置上下文</li><li>忽略子代理问题</li><li>在规格符合✅前开始代码质量审查（顺序错误）</li><li>带任一审查未解决时移到下个任务</li></ul><h2 id="九、git-工作树-隔离开发" tabindex="-1">九、Git 工作树：隔离开发 <a class="header-anchor" href="#九、git-工作树-隔离开发" aria-label="Permalink to &quot;九、Git 工作树：隔离开发&quot;">​</a></h2><h3 id="核心原则-8" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则-8" aria-label="Permalink to &quot;核心原则&quot;">​</a></h3><p><strong>用 Git 工作树创建隔离开发环境，保持主分支清洁。</strong></p><p>在开始任何需要隔离的功能工作前，创建工作树：</p><ul><li>不污染主分支</li><li>并行多个功能分支</li><li>快速丢弃坏实验</li></ul><h2 id="十、常见反模式总结" tabindex="-1">十、常见反模式总结 <a class="header-anchor" href="#十、常见反模式总结" aria-label="Permalink to &quot;十、常见反模式总结&quot;">​</a></h2><h3 id="_12-种-ai-代理会使用的合理化借口" tabindex="-1">12 种 AI 代理会使用的合理化借口 <a class="header-anchor" href="#_12-种-ai-代理会使用的合理化借口" aria-label="Permalink to &quot;12 种 AI 代理会使用的合理化借口&quot;">​</a></h3><table tabindex="0"><thead><tr><th>序号</th><th>借口类型</th><th>示例</th><th>应对</th></tr></thead><tbody><tr><td>1</td><td><strong>&quot;简单&quot;借口</strong></td><td>&quot;这很简单，不用技能&quot;</td><td>1% 原则，必须调用</td></tr><tr><td>2</td><td><strong>&quot;之后&quot;借口</strong></td><td>&quot;我之后再写测试/再调查&quot;</td><td>现在做，之后无意义</td></tr><tr><td>3</td><td><strong>&quot;快速修复&quot;借口</strong></td><td>&quot;快速修这个，以后调查&quot;</td><td>无根因不修复</td></tr><tr><td>4</td><td><strong>&quot;手动测试&quot;借口</strong></td><td>&quot;我手动测过了，没问题&quot;</td><td>手动≠自动，无记录</td></tr><tr><td>5</td><td><strong>&quot;沉没成本&quot;借口</strong></td><td>&quot;已经花 X 小时，删除浪费&quot;</td><td>沉没成本谬误，删掉重来</td></tr><tr><td>6</td><td><strong>&quot;参考&quot;借口</strong></td><td>&quot;保留代码作参考&quot;</td><td>你会调整它，删掉重来</td></tr><tr><td>7</td><td><strong>&quot;务实&quot;借口</strong></td><td>&quot;TDD 教条，我很务实&quot;</td><td>实用=遵循流程</td></tr><tr><td>8</td><td><strong>&quot;探索&quot;借口</strong></td><td>&quot;让我先探索代码&quot;</td><td>技能告诉你如何探索</td></tr><tr><td>9</td><td><strong>&quot;记得&quot;借口</strong></td><td>&quot;我记得这个技能&quot;</td><td>每次读最新版</td></tr><tr><td>10</td><td><strong>&quot;紧急&quot;借口</strong></td><td>&quot;紧急，没时间走流程&quot;</td><td>流程更快，乱试更慢</td></tr><tr><td>11</td><td><strong>&quot;部分验证&quot;借口</strong></td><td>&quot;Linter 过了&quot;</td><td>部分验证什么都没有</td></tr><tr><td>12</td><td><strong>&quot;疲劳&quot;借口</strong></td><td>&quot;我累了，先这样吧&quot;</td><td>疲劳不是借口，验证再声称</td></tr></tbody></table><h3 id="立即停止信号" tabindex="-1">立即停止信号 <a class="header-anchor" href="#立即停止信号" aria-label="Permalink to &quot;立即停止信号&quot;">​</a></h3><p>当听到以下信号时，<strong>立即停止并返回正确的流程</strong>：</p><table tabindex="0"><thead><tr><th>信号</th><th>含义</th><th>正确行动</th></tr></thead><tbody><tr><td>&quot;这不是？&quot;</td><td>你未经验证就假设了</td><td>验证你的假设</td></tr><tr><td>&quot;它会展示我们...？&quot;</td><td>你应该加证据收集</td><td>回到根因调查</td></tr><tr><td>&quot;停止猜测&quot;</td><td>你未理解就提方案</td><td>完成根因调查</td></tr><tr><td>&quot;深入思考这个问题&quot;</td><td>质疑基础，不只症状</td><td>回到根本问题</td></tr><tr><td>&quot;我们卡住了？&quot;（沮丧）</td><td>你的方法不工作</td><td>重新分析问题</td></tr></tbody></table><h2 id="十一、与-ai-代理协作的黄金法则" tabindex="-1">十一、与 AI 代理协作的黄金法则 <a class="header-anchor" href="#十一、与-ai-代理协作的黄金法则" aria-label="Permalink to &quot;十一、与 AI 代理协作的黄金法则&quot;">​</a></h2><h3 id="建立信任的七条准则" tabindex="-1">建立信任的七条准则 <a class="header-anchor" href="#建立信任的七条准则" aria-label="Permalink to &quot;建立信任的七条准则&quot;">​</a></h3><ol><li><strong>铁律不可商量</strong>：TDD、调试、证据等铁律不是选项</li><li><strong>证据优于声称</strong>：没看到输出前不相信任何完成声明</li><li><strong>识别合理化</strong>：AI 会找各种借口，必须识别并阻止</li><li><strong>早期审查</strong>：每个任务后审查，不堆到 PR 一起</li><li><strong>系统化流程</strong>：不跳过任何步骤，即使是&quot;简单&quot;任务</li><li><strong>尊重优先级</strong>：流程技能优先于实现技能</li><li><strong>相信验证</strong>：只有看到命令输出和证据才相信完成</li></ol><h3 id="建立高效工作习惯" tabindex="-1">建立高效工作习惯 <a class="header-anchor" href="#建立高效工作习惯" aria-label="Permalink to &quot;建立高效工作习惯&quot;">​</a></h3><div class="tip custom-block"><p class="custom-block-title">推荐做法</p><p>每次对话开始时，你可以对 AI 说：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请严格遵循 Superpowers 技能。即使觉得没必要，</span></span>
<span class="line"><span>也必须先调用相关技能。所有&quot;简单&quot;、&quot;快速&quot;、</span></span>
<span class="line"><span>&quot;之后&quot;等合理化借口都被禁止。</span></span></code></pre></div><p>这样可以建立期望，让 AI 代理知道你会严格执行。</p></div><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p>Superpowers 的核心价值不是让 AI 更聪明，而是让 AI&quot;听话&quot;：</p><ul><li><strong>1% 原则</strong>防止 AI 跳过必要检查</li><li><strong>TDD 铁律</strong>确保代码可测试、可维护</li><li><strong>调试铁律</strong>避免盲目修复和问题复发</li><li><strong>证据铁律</strong>建立信任基线，拒绝虚假进度</li><li><strong>审查铁律</strong>早期发现问题，减少后期返工</li></ul><p>识别并阻止 AI 代理的 12 种常见合理化借口，你将获得：</p><ul><li>更高的代码质量</li><li>更快的开发速度（减少返工）</li><li>更稳定的交付（系统化流程）</li><li>更好的协作体验（信任建立）</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../../appendix/skills-reference/">技能完整参考</a></strong>。</p><p>你将学到：</p><ul><li>14 个技能的快速参考表</li><li>每个技能的触发条件和核心要点</li><li>如何快速找到需要的技能</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-02-01</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>技能调用铁律与 1% 原则</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/using-superpowers/SKILL.md#L6-L12" target="_blank" rel="noreferrer"><code>skills/using-superpowers/SKILL.md</code></a></td><td>6-12, 24, 48-66</td></tr><tr><td>TDD 铁律与 RED-GREEN-REFACTOR</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/test-driven-development/SKILL.md#L31-L45" target="_blank" rel="noreferrer"><code>skills/test-driven-development/SKILL.md</code></a></td><td>31-45, 47-69, 272-289</td></tr><tr><td>系统化调试四阶段流程</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/systematic-debugging/SKILL.md#L16-L45" target="_blank" rel="noreferrer"><code>skills/systematic-debugging/SKILL.md</code></a></td><td>16-45, 50-122, 215-232</td></tr><tr><td>证据优先闸门函数</td><td><a href="https://github.com/obra/superpowers/blob/main/skills/verification-before-completion/SKILL.md#L16-L38" target="_blank" rel="noreferrer"><code>skills/verification-before-completion/SKILL.md</code></a></td><td>16-38, 52-62, 64-75</td></tr><tr><td>代码审查铁律与 Red Flags</td><td>[<code>skills/requesting-code-review/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/requesting-code-review/SKILL.md#L10-L12" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/requesting-code-review/SKILL.md#L10-L12</a>, 92-99)</td><td>10-12, 92-99</td></tr><tr><td>子代理驱动两阶段审查</td><td>[<code>skills/subagent-driven-development/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/subagent-driven-development/SKILL.md#L10-L11" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/subagent-driven-development/SKILL.md#L10-L11</a>, 199-214)</td><td>10-11, 199-214</td></tr><tr><td>计划编写原则（DRY、YAGNI、TDD）</td><td>[<code>skills/writing-plans/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/writing-plans/SKILL.md#L10-L12" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/writing-plans/SKILL.md#L10-L12</a>, 90-96)</td><td>10-12, 90-96</td></tr><tr><td>设计阶段原则（一次一个问题）</td><td>[<code>skills/brainstorming/SKILL.md</code>](<a href="https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md#L16-L21" target="_blank" rel="noreferrer">https://github.com/obra/superpowers/blob/main/skills/brainstorming/SKILL.md#L16-L21</a>, 47-54)</td><td>16-21, 47-54</td></tr></tbody></table><p><strong>关键常量</strong>：</p><ul><li>无硬编码常量，技能系统基于文件动态加载</li></ul><p><strong>关键函数</strong>：</p><ul><li>无函数定义，技能系统基于 Markdown 文件和 YAML frontmatter</li></ul></details>`,106)])])}const g=a(o,[["render",i]]);export{q as __pageData,g as default};
